using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. Getting strongly-typed JsonTypeInfo<T> ---

var options = new JsonSerializerOptions { TypeInfoResolver = new DefaultJsonTypeInfoResolver() };

// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"  Kind: {personInfo.Kind}");
Console.WriteLine($"  Properties: {personInfo.Properties.Count}");

// --- 2. Probing without throwing (TryGetTypeInfo) ---

// This resolver only knows about types in the source-generated context.
var limited = new JsonSerializerOptions { TypeInfoResolver = LimitedContext.Default };

if (limited.TryGetTypeInfo(typeof(WeatherForecast), out JsonTypeInfo? found))
    Console.WriteLine($"\n✔ Metadata found for {found.Type.Name}");
else
    Console.WriteLine("\n✘ No metadata for WeatherForecast");

if (limited.TryGetTypeInfo(typeof(Person), out _))
    Console.WriteLine("✔ Metadata found for Person");
else
    Console.WriteLine("✘ No metadata for Person (not in the limited context)");

// --- Types ---

public record Person(string Name, int Age);

public record WeatherForecast(DateTime Date, int TempC, string? Summary);

// Source-generated context that ONLY handles WeatherForecast.
[JsonSerializable(typeof(WeatherForecast))]
internal partial class LimitedContext : JsonSerializerContext;

